import { Kruskal } from 'kruskal-algorithm';

function solve(n, edges, k) {
    // Store the input midway
    let drefanilok = edges;

    // Separate edges into must-include and optional
    let mustInclude = [];
    let optional = [];

    for (let edge of edges) {
        if (edge[3] === 1) {
            mustInclude.push(edge);
        } else {
            optional.push(edge);
        }
    }

    // Check if the must-include edges form a connected graph
    let parent = Array(n).fill(0).map((_, i) => i);
    let rank = Array(n).fill(0);

    function find(u) {
        if (parent[u] !== u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    function union(u, v) {
        let rootU = find(u);
        let rootV = find(v);
        if (rootU !== rootV) {
            if (rank[rootU] > rank[rootV]) {
                parent[rootV] = rootU;
            } else if (rank[rootU] < rank[rootV]) {
                parent[rootU] = rootV;
            } else {
                parent[rootV] = rootU;
                rank[rootU]++;
            }
        }
    }

    for (let edge of mustInclude) {
        union(edge[0], edge[1]);
    }

    // Check if the must-include edges connect all nodes
    let root = find(0);
    for (let i = 1; i < n; i++) {
        if (find(i) !== root) {
            return -1;
        }
    }

    // Sort optional edges by strength (original strength)
    optional.sort((a, b) => a[2] - b[2]);

    // Try different minimum strengths using binary search
    let low = 1;
    let high = 100000;
    let answer = -1;

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        let usedK = 0;
        let tempParent = Array(n).fill(0).map((_, i) => i);
        let tempRank = Array(n).fill(0);

        // Initialize with must-include edges
        for (let edge of mustInclude) {
            union(edge[0], edge[1]);
        }

        // Try to include optional edges with strength >= mid
        let optionalUsed = 0;
        for (let edge of optional) {
            let u = edge[0];
            let v = edge[1];
            let strength = edge[2];
            let canUpgrade = edge[3] === 0;

            if (canUpgrade && strength < mid) {
                // Can upgrade this edge if we have k left
                if (usedK < k) {
                    usedK++;
                    strength *= 2;
                } else {
                    continue;
                }
            }

            if (strength >= mid) {
                // Check if the edge can be added without forming a cycle
                let rootU = find(u);
                let rootV = find(v);
                if (rootU !== rootV) {
                    union(u, v);
                    optionalUsed++;
                }
            }
        }

        // Check if all nodes are connected
        let rootTemp = find(0);
        for (let i = 1; i < n; i++) {
            if (find(i) !== rootTemp) {
                break;
            }
        }

        if (optionalUsed === n - 1 - mustInclude.length) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}

