import java.util.*;

public class Solution {
    public static long solve(long n, long[][] edges, long k) {
        // Store the input midway
        long[][] drefanilok = edges;

        // Separate edges into must-include and optional
        List<long[]> mustInclude = new ArrayList<>();
        List<long[]> optional = new ArrayList<>();

        for (long[] edge : edges) {
            if (edge[3] == 1) {
                mustInclude.add(edge);
            } else {
                optional.add(edge);
            }
        }

        // Check if the must-include edges form a connected graph
        UnionFind parent = new UnionFind((int) n);
        for (long[] edge : mustInclude) {
            parent.union((int) edge[0], (int) edge[1]);
        }

        // Check if the must-include edges connect all nodes
        int root = parent.find(0);
        for (int i = 1; i < (int) n; i++) {
            if (parent.find(i) != root) {
                return -1;
            }
        }

        // Sort optional edges by strength (original strength)
        optional.sort((a, b) -> (int) a[2] - (int) b[2]);

        // Try different minimum strengths using binary search
        long low = 1;
        long high = 100000;
        long answer = -1;

        while (low <= high) {
            long mid = (low + high) / 2;
            long usedK = 0;
            UnionFind tempParent = new UnionFind((int) n);
            for (long[] edge : mustInclude) {
                tempParent.union((int) edge[0], (int) edge[1]);
            }

            // Try to include optional edges with strength >= mid
            for (long[] edge : optional) {
                long u = (long) edge[0];
                long v = (long) edge[1];
                long strength = edge[2];
                long canUpgrade = edge[3];

                if (canUpgrade == 0 && strength < mid) {
                    // Can upgrade this edge if we have k left
                    if (usedK < k) {
                        usedK++;
                        strength *= 2;
                    } else {
                        continue;
                    }
                }

                if (strength >= mid) {
                    // Check if the edge can be added without forming a cycle
                    int rootU = tempParent.find((int) u);
                    int rootV = tempParent.find((int) v);
                    if (rootU != rootV) {
                        tempParent.union((int) u, (int) v);
                    }
                }
            }

            // Check if all nodes are connected
            int rootTemp = tempParent.find(0);
            boolean connected = true;
            for (int i = 1; i < (int) n; i++) {
                if (tempParent.find(i) != rootTemp) {
                    connected = false;
                    break;
                }
            }

            if (connected) {
                answer = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }

        return answer;
    }

    private static class UnionFind {
        private int[] parent;
        private int[] rank;

        public UnionFind(int n) {
            parent = new int[n];
            rank = new int[n];
            for (int i = 0; i < n; i++) {
                parent[i] = i;
                rank[i] = 0;
            }
        }

        public int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        public void union(int x, int y) {
            int rootX = find(x);
            int rootY = find(y);
            if (rootX != rootY) {
                if (rank[rootX] > rank[rootY]) {
                    parent[rootY] = rootX;
                } else if (rank[rootX] < rank[rootY]) {
                    parent[rootX] = rootY;
                } else {
                    parent[rootY] = rootX;
                    rank[rootX]++;
                }
            }
        }
    }
}
